SELECT WLF_UNIQ_NO, WLF_ISTU_CLS_CNTT, WLF_FLNM_CNTT, WLF_FIRST_NAME_CNTT, WLF_MIDDLE_NAME_CNTT, WLF_LAST_NAME_CNTT, WLF_NTNT_CNTT, WLF_POB_CNTT, WLF_RSPS_CNTT, WLF_RGNO_CNTT, SPLM_DATE, FLXB_YN FROM NIC19B_FACTIVA_UA
AND (WLF_FLNM_CNTT LIKE CONCAT('%', #{searchName}, '%') OR WLF_FIRST_NAME_CNTT LIKE CONCAT('%', #{searchName}, '%') OR WLF_LAST_NAME_CNTT LIKE CONCAT('%', #{searchName}, '%'))
AND (WLF_FLNM_CNTT LIKE CONCAT('%', #{wlNm}, '%') OR WLF_FIRST_NAME_CNTT LIKE CONCAT('%', #{wlNm}, '%') OR WLF_LAST_NAME_CNTT LIKE CONCAT('%', #{wlNm}, '%'))
AND WLF_ISTU_CLS_CNTT = #{category}
AND WLF_ISTU_CLS_CNTT = #{wlTpCd}
AND WLF_NTNT_CNTT = #{natCd}
AND WLF_NTNT_CNTT = #{wlSrcCd}
ORDER BY WLF_UNIQ_NO DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC19B_FACTIVA_UA


        AND (WLF_FLNM_CNTT LIKE CONCAT('%', #{searchName}, '%')
          OR WLF_FIRST_NAME_CNTT LIKE CONCAT('%', #{searchName}, '%')
          OR WLF_LAST_NAME_CNTT LIKE CONCAT('%', #{searchName}, '%'))


