          OR WLF_FIRST_NAME_CNTT LIKE CONCAT('%', #{wlNm}, '%')
          OR WLF_LAST_NAME_CNTT LIKE CONCAT('%', #{wlNm}, '%'))


        AND WLF_ISTU_CLS_CNTT = #{category}


        AND WLF_ISTU_CLS_CNTT = #{wlTpCd}


